const fs = require('fs');
const vm = require('vm');
const path = 'index.html';
let s = fs.readFileSync(path, 'utf8');

const visualCss = `
/* codex-flow-visual-20260518 */
.flow-visual{margin-top:14px;border:1px solid rgba(24,60,74,.16);border-radius:10px;background:linear-gradient(180deg,#ffffff,#f6fbf8);padding:12px;display:grid;gap:10px}
.flow-visual-head{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:8px}.flow-chip{border:1px solid rgba(24,60,74,.14);border-radius:8px;background:#fff;padding:9px 10px}.flow-chip span{display:block;color:#66757c;font-size:12px}.flow-chip strong{display:block;margin-top:4px;font-size:20px;color:#0b1a2d}.flow-bars{display:grid;gap:9px}.flow-row{display:grid;grid-template-columns:82px minmax(0,1fr) 54px;gap:10px;align-items:center}.flow-name{font-weight:900;color:#10242d}.flow-pair{display:grid;gap:5px}.mini-bar{height:10px;border-radius:999px;background:#e6edf0;overflow:hidden}.mini-fill{height:100%;border-radius:999px}.mini-fill.inst{background:linear-gradient(90deg,#1d7ff2,#55d7ff)}.mini-fill.tax{background:linear-gradient(90deg,#d7a93e,#ffd86b)}.flow-label{font-size:11px;color:#66757c;display:flex;justify-content:space-between}.flow-score{text-align:right;font-weight:900;color:#10242d}.flow-note-text{margin:0;color:#66757c;line-height:1.65}@media(max-width:720px){.flow-visual-head{grid-template-columns:1fr}.flow-row{grid-template-columns:64px minmax(0,1fr) 46px}}
`;
if (!s.includes('codex-flow-visual-20260518')) s = s.replace('</style>', visualCss + '</style>');

const fastVix = `async function fetchVixOnce(){var box=document.querySelector("#vixTicker"),val=document.querySelector("#vixValue"),time=document.querySelector("#vixTime");if(!box||!val||!time)return null;time.textContent="快速抓取";function apply(v,src){v=Number(v);if(!Number.isFinite(v)||v<=0)throw new Error("bad vix");state.lastVix={value:v,time:new Date(),source:src};val.textContent=v.toFixed(2);time.textContent=src;box.classList.toggle("hot",v>=25);box.classList.toggle("calm",v<18);return state.lastVix}function timeout(ms){return new Promise((_,rej)=>setTimeout(()=>rej(new Error("timeout")),ms))}async function yahoo(url,src){var r=await Promise.race([fetch(url,{cache:"no-store"}),timeout(2600)]);if(!r.ok)throw new Error("status");var d=await r.json();var x=d.chart&&d.chart.result&&d.chart.result[0];var q=(x&&x.indicators&&x.indicators.quote&&x.indicators.quote[0]&&x.indicators.quote[0].close)||[];var last=[].concat(q).reverse().find(function(n){return Number.isFinite(Number(n))});return apply((x&&x.meta&&x.meta.regularMarketPrice)||last,src)}async function stooq(){var u="https://api.allorigins.win/raw?url="+encodeURIComponent("https://stooq.com/q/l/?s=%5Evix&f=sd2t2ohlcv&h&e=csv&_="+Date.now());var r=await Promise.race([fetch(u,{cache:"no-store"}),timeout(2600)]);if(!r.ok)throw new Error("status");var txt=await r.text();var cols=(txt.trim().split(String.fromCharCode(10))[1]||"").split(',');return apply(cols[6]||cols[3]||cols[4],"Stooq 最新")}var direct="https://query1.finance.yahoo.com/v8/finance/chart/%5EVIX?range=1d&interval=1m&corsDomain=finance.yahoo.com&_="+Date.now();var proxy="https://api.allorigins.win/raw?url="+encodeURIComponent("https://query1.finance.yahoo.com/v8/finance/chart/%5EVIX?range=1d&interval=1m&_="+Date.now());try{return await Promise.any([yahoo(direct,"Yahoo 即時"),yahoo(proxy,"Yahoo 最新"),stooq()])}catch(e){state.lastVix=null;val.textContent="重試";time.textContent="請再按生成";box.classList.remove("hot","calm");return null}}`;
s = s.replace(/async function fetchVixOnce\(\)\{[\s\S]*?function vixText\(\)/, fastVix + 'function vixText()');
s = s.replace(/function vixText\(\)\{[^}]*\}/, 'function vixText(){return state.lastVix?"VIX "+num(state.lastVix.value,2)+"（"+(state.lastVix.source||"本次生成時抓取")+"）":"VIX 本次未取得最新資料，仍以持股結構與風控數據先做判斷"}');

const techReview = `function review(s,t){els.emptyState.hidden=true;els.reviewOutput.hidden=false;const final=conclusion(s);const largest=s.largest?\`${'${s.largest.name} ${pct(s.largest.weight)}'}\`:'尚無';const sector=s.sectors.map(([n,w])=>\`${'${n} ${pct(w)}'}\`).join('、')||'尚無資料';const market=els.marketContext.value.trim()||'尚未輸入大盤脈絡，本次先用持股水位、集中度、損益結構、VIX 與籌碼推算判斷。';const watch=(s.watch.length?s.watch:state.analyzed).slice(0,6).map(r=>\`${'${r.name}：${r.status}，占比 ${pct(r.weight)}，損益率 ${pct(r.pnlPct)}'}\`).join('；')||'尚無需要優先檢討標的';els.reviewOutput.innerHTML=\`<div class="review-brief"><h3>複盤重點整理</h3><div class="brief-grid"><div class="brief-card"><span>股票水位</span><strong>${'${pct(s.stockRatio)}'}</strong></div><div class="brief-card"><span>最大部位</span><strong>${'${s.largest?pct(s.largest.weight):\'0%\'}'}</strong></div><div class="brief-card"><span>需檢討</span><strong>${'${s.watch.length}'}</strong></div><div class="brief-card"><span>未實現損益</span><strong>${'${money(s.totalPnl)}'}</strong></div></div><div class="brief-conclusion"><strong>下複盤後的總結論</strong>${'${esc(final)}'}<br><br><b>目前股票水位</b> ${'${pct(s.stockRatio)}'}，<b>最大部位</b> ${'${esc(largest)}'}，<b>需檢討檔數</b> ${'${s.watch.length}'}。<br><b>VIX 市場風險溫度：</b>${'${esc(vixText())}'}。</div><p class="brief-note">複盤已生成：以下是完整 10 段專業回顧，白色總結卡已移除，只保留科技感總結區。</p></div>\`+[['水位與攻守',\`股票水位 ${'${pct(s.stockRatio)}'}，屬於「${'${s.water}'}」。水位偏高時先管風險，水位偏低時保留加碼彈性。\`],['集中度',\`最大部位 ${'${largest}'}。集中度觀察：${'${names(s.con,\'目前沒有單一部位超過上限\')}'}。\`],['產業配置',\`產業/市場分布：${'${sector}'}。若多檔集中在同一題材，實際風險會高於表面檔數。\`],['個股檢視',watch],['大盤脈絡',market],['VIX 風險',\`${'${vixText()}'}。VIX 升高時降低高 beta 與高位階部位，VIX 偏低時避免過度追價。\`],['機構與政策','智慧工具的「機構資金與籌碼流向」已依你的實際持股推算機構占比與政府稅改受惠比例。'],['資金效率',\`弱勢標的 ${'${s.weak.length}'}，高位階標的 ${'${s.high.length}'}。資金應優先留給邏輯清楚、位階合理、籌碼穩定的部位。\`],['估值檢查','目標價工具可用最新公開資料評估低標、最可能目標價與高標，避免只用單一機構觀點。'],['執行結論',final]].map((x,i)=>\`<section class="section" style="--tone:${'${[\'#183c4a\',\'#456aa8\',\'#147a78\',\'#147a78\',\'#d7a93e\',\'#bd4f48\',\'#456aa8\',\'#456aa8\',\'#d7a93e\',\'#437f53\'][i]}'}"><b>${'${i+1}'}</b><article><h3>${'${esc(x[0])}'}</h3><p>${'${esc(x[1])}'}</p></article></section>\`).join('')}`;
s = s.replace(/function review\(s,t\)\{[\s\S]*?\}function fourQ\(/, techReview + 'function fourQ(');
s = s.replace(/\nreview=function\(s,t\)\{[\s\S]*?\n\}\nfunction leaderName\(/, '\nfunction leaderName(');

const taxFn = `function estimateTaxPolicyBenefit(r){const text=(r.symbol+' '+r.name+' '+r.sector).toUpperCase();let score=35;if(/GEV|GRID|POWER|ENERGY|VERNOVA|LIN|LINDE|UTILITY|ELECTRIC/.test(text))score+=24;if(/TSM|TSMC|AMAT|ASML|NVDA|SEMICONDUCTOR|CHIP|AI|TECH|DATA CENTER/.test(text))score+=18;if(/US|USA|AMERICA|UNITED STATES/.test(text))score+=8;if(/TSLA|EV|CLEAN|SOLAR|WIND|BATTERY/.test(text))score+=10;if(r.weight>.15)score+=4;if(r.isHigh)score-=3;if(r.isWeak)score-=5;return Math.max(10,Math.min(88,score))}`;
if (s.includes('function estimateTaxPolicyBenefit')) s = s.replace(/function estimateTaxPolicyBenefit\(r\)\{[\s\S]*?\}function flowMetrics\(/, taxFn + 'function flowMetrics(');
else s = s.replace('function flowMetrics(s,t){', taxFn + 'function flowMetrics(s,t){');

const flowFn = `function flowMetrics(s,t){if(!els.flowNet)return;const rows=state.analyzed||[],totalWeight=rows.reduce((sum,r)=>sum+r.weight,0)||1;const weightedOwnership=rows.reduce((sum,r)=>sum+estimateInstitutionOwnership(r)*r.weight,0)/totalWeight;const weightedTax=rows.reduce((sum,r)=>sum+estimateTaxPolicyBenefit(r)*r.weight,0)/totalWeight;const bullish=rows.filter(r=>r.pnlPct>0&&!r.isHigh).length,weak=s.weak.length,con=s.con.length;const rowHtml=rows.slice(0,8).map(r=>{const inst=estimateInstitutionOwnership(r),tax=estimateTaxPolicyBenefit(r),mix=Math.round(inst*.6+tax*.4);return '<div class="flow-row"><div class="flow-name">'+esc(r.symbol)+'</div><div class="flow-pair"><div class="flow-label"><span>機構持股</span><b>'+num(inst,0)+'%</b></div><div class="mini-bar"><div class="mini-fill inst" style="width:'+Math.max(4,inst)+'%"></div></div><div class="flow-label"><span>稅改受惠</span><b>'+num(tax,0)+'%</b></div><div class="mini-bar"><div class="mini-fill tax" style="width:'+Math.max(4,tax)+'%"></div></div></div><div class="flow-score">'+mix+'</div></div>'}).join('');const topOwners=rows.slice(0,5).map(r=>r.symbol+' 機構'+num(estimateInstitutionOwnership(r),0)+'% / 稅改'+num(estimateTaxPolicyBenefit(r),0)+'%').join('、');const buy=Math.max(15,Math.min(85,Math.round(38+weightedOwnership*.34+weightedTax*.18+(bullish-weak)*4-con*3)));const sell=100-buy;const netUsd=(t.stock/32/100000000)*(buy-sell)/100*2.2;els.flowNet.textContent=(netUsd>=0?'+':'')+num(netUsd,1)+' 億美元';els.flowNetCard.classList.toggle('positive',netUsd>=0);els.flowNetCard.classList.toggle('negative',netUsd<0);els.flowOwnership.textContent=num(weightedOwnership,1)+'%';els.flowBuyBar.style.width=buy+'%';els.flowBuy.textContent='買進 '+buy+'%';els.flowSell.textContent='賣出 '+sell+'%';els.flowNote.innerHTML='<div class="flow-visual"><div class="flow-visual-head"><div class="flow-chip"><span>機構持股加權</span><strong>'+num(weightedOwnership,1)+'%</strong></div><div class="flow-chip"><span>政府稅改受惠</span><strong>'+num(weightedTax,1)+'%</strong></div><div class="flow-chip"><span>買賣力道</span><strong>'+buy+' / '+sell+'</strong></div></div><div class="flow-bars">'+rowHtml+'</div><p class="flow-note-text">依你的實際持股逐檔推算：'+esc(topOwners||'尚無持股')+'。藍色為機構持股推算，金色為政府稅改受惠推算，右側分數為籌碼與政策綜合分。</p></div>'}`;
s = s.replace(/function flowMetrics\(s,t\)\{[\s\S]*?\}function smart\(/, flowFn + 'function smart(');

s = s.replace(/split\(\/\r?\n\/\)/g, 'split(String.fromCharCode(10))');
fs.writeFileSync(path, s);
const html = fs.readFileSync(path, 'utf8');
const script = html.slice(html.indexOf('<script>') + 8, html.lastIndexOf('</script>'));
new vm.Script(script, { filename: 'index.inline.js' });
